module top_module(
    input [7:0] obf_x,
    output reg z
    );task calc_even_parity;
        input [7:0] obf_x;
        output z;
        begin
            z = obf_x[7]^obf_x[6]^obf_x[5]^obf_x[4]^obf_x[3]^obf_x[2]^obf_x[1]^obf_x[0];
        end
    endtask
    always
        @ (obf_x)
        begin
            calc_even_parity(obf_x,z);
        end

endmodule
